package com.agrios.platform.serviceappointment.domain;
import jakarta.persistence.*; import java.time.Instant; import java.util.UUID;
@Entity @Table(name="appointment",schema="service")
public class AppointmentEntity { @Id private UUID id; @Column(nullable=false) private UUID tenantId; @Column(nullable=false) private UUID providerId; private UUID availabilityId; @Column(nullable=false) private UUID farmerId; private UUID farmId; private UUID fieldId; private UUID cropCycleId; @Column(nullable=false) private String subjectType; private UUID subjectReferenceId; @Column(nullable=false) private String appointmentType; @Column(nullable=false) private String mode; @Column(nullable=false) private Instant scheduledStartAt; @Column(nullable=false) private Instant scheduledEndAt; private String locationText; @Column(nullable=false,columnDefinition="text") private String problemSummary; @Column(nullable=false) private String status; @Column(columnDefinition="text") private String cancellationReason; private UUID requestedBy; @Column(columnDefinition="text") private String providerNotes; @Version private long version; @Column(nullable=false) private Instant createdAt; @Column(nullable=false) private Instant updatedAt; protected AppointmentEntity(){} public static AppointmentEntity create(UUID tenantId,UUID providerId,UUID availabilityId,UUID farmerId,UUID farmId,UUID fieldId,UUID cropCycleId,String subjectType,UUID subjectReferenceId,String type,String mode,Instant start,Instant end,String location,String problem,UUID actor){var v=new AppointmentEntity();v.id=UUID.randomUUID();v.tenantId=tenantId;v.providerId=providerId;v.availabilityId=availabilityId;v.farmerId=farmerId;v.farmId=farmId;v.fieldId=fieldId;v.cropCycleId=cropCycleId;v.subjectType=subjectType;v.subjectReferenceId=subjectReferenceId;v.appointmentType=type;v.mode=mode;v.scheduledStartAt=start;v.scheduledEndAt=end;v.locationText=location;v.problemSummary=problem;v.status="REQUESTED";v.requestedBy=actor;v.createdAt=Instant.now();v.updatedAt=v.createdAt;return v;} public void transition(String next,String reason){status=next;cancellationReason=reason;updatedAt=Instant.now();} public void complete(String notes){status="COMPLETED";providerNotes=notes;updatedAt=Instant.now();} public UUID id(){return id;} public UUID providerId(){return providerId;} public UUID farmerId(){return farmerId;} public String status(){return status;} public String appointmentType(){return appointmentType;} public String mode(){return mode;} public Instant scheduledStartAt(){return scheduledStartAt;} public Instant scheduledEndAt(){return scheduledEndAt;} public String problemSummary(){return problemSummary;} public long version(){return version;}}
